// This program implements a sorting algorithm that can be evolved to adapt to different data patterns

use std::cmp::Ordering;

// EVOLVE-BLOCK-START
// Initial implementation: Simple quicksort
// This can be evolved to:
// - Hybrid algorithms (introsort, timsort-like)
// - Adaptive pivot selection
// - Special handling for nearly sorted data
// - Switching to different algorithms based on data characteristics

pub fn adaptive_sort<T: Ord + Clone>(arr: &mut [T]) {
    let n = arr.len();
    if n <= 16 { insertion_sort(arr); return; }

    let mut inv = 0;
    for w in arr.windows(2) { if w[0] > w[1] { inv += 1; } }

    if inv <= n / 7 {
        insertion_sort(arr);
    } else if inv >= n.saturating_sub(n / 7 + 1) {
        arr.reverse();
        insertion_sort(arr);
    } else {
        quicksort(arr, 0, n - 1);
    }
}

fn quicksort<T: Ord + Clone>(arr: &mut [T], mut low: usize, mut high: usize) {
    while low < high {
        if high - low < 16 {
            insertion_sort(&mut arr[low..=high]);
            break;
        }
        let p = partition(arr, low, high);
        if p - low < high - p {
            if p > 0 { quicksort(arr, low, p - 1); }
            low = p + 1;
        } else {
            quicksort(arr, p + 1, high);
            if p > 0 { high = p - 1; } else { break; }
        }
    }
}

fn partition<T: Ord + Clone>(arr: &mut [T], low: usize, high: usize) -> usize {
    // Median-of-three pivot selection
    let mid = low + (high - low) / 2;
    if arr[mid] < arr[low] { arr.swap(low, mid); }
    if arr[high] < arr[low] { arr.swap(low, high); }
    if arr[mid] < arr[high] { arr.swap(mid, high); }

    let pivot = arr[high].clone();
    let mut i = low;

    for j in low..high {
        if arr[j] <= pivot {
            if i != j { arr.swap(i, j); }
            i += 1;
        }
    }

    arr.swap(i, high);
    i
}



